var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"기세 좋게 덤빌 땐 언제고, 도망치기에만 급급한가?","JPN":"勢いよく飛び掛かっておいて、いつまで逃げまわるつもりだ？","ENG":"You were bold when charging in. Why so desperate to flee now?","TWN":"剛才氣勢洶洶地衝過來，現在只顧著逃跑了嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"네놈들이 벗어날 곳은 없으니 어디 신명나게 덤벼 보아라.","JPN":"お前らに逃げ場などない。存分にかかって来い。","ENG":"There's nowhere left to run. Come on then, give me a real fight.","TWN":"你們無處可逃，放馬過來，讓我看看你們有多瘋狂。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"음…","JPN":"うーん……","ENG":"Hmm…","TWN":"嗯…"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"하담아, 느껴지느냐? 놈이 점점 더 강해지고 있구나.","JPN":"カタン、分かるか。やつがどんどん強くなってきている。","ENG":"Ha Dam, can you feel it? The Tiger's growing stronger.","TWN":"夏垣，你感覺到了嗎？那傢伙越來越強了。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"놈은… 짐승의 껍데기를 초월하여 마왕이란 것이 되려 하는 거요.","JPN":"やつは……ケモノの皮を超越し、魔王というものになろうとしている。","ENG":"It… seeks to transcend the shell of a Beast and become something greater, a Demon Lord.","TWN":"那傢伙…正超越野獸的外殼，試圖成為魔王。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"마왕이라…","JPN":"魔王か……","ENG":"A Demon Lord…","TWN":"魔王啊…"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그것이 목표라면, 지금껏 제법 많은 힘을 모아뒀겠구나.","JPN":"それがやつの狙いなら、今までかなりの力を蓄えているだろう。","ENG":"If that's the goal, it's probably gathered plenty of power by now.","TWN":"如果那是目標，想必牠已經積累了相當多的力量。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"생전 연화가 입힌 범 목덜미의 상처가 아직 아물지 않았소.","JPN":"生前のレンカが残した虎の首の傷跡が、まだ癒えてなかった。","ENG":"The wound Yeonhwa inflicted on its neck still hasn't healed.","TWN":"蓮華生前在牠脖頸上留下的傷口還沒有癒合。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"본인이 어떻게든 주의를 끌 테니, 저것을 노려주시게.","JPN":"某がなんとか気を引く。あそこを狙ってくれ。","ENG":"I'll draw its attention. Aim for that spot.","TWN":"我會想辦法吸引牠的注意力，你去攻擊那裡。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그렇구나. 저 목의 틈을 노려 벤다면 승산이 있겠지.","JPN":"なるほど。あの首の継ぎ目を斬れば、勝ち目があるかもしれないな。","ENG":"I see. If we can land a strike there, we might have a shot at this.","TWN":"原來如此。瞄準他脖子的縫隙斬下去，就有勝算。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허나 저놈 또한 보란 듯 목의 상처를 드러내고 있으니, 뻔한 노림수다.","JPN":"しかしやつはこれ見よがしに首の傷を晒している。あれは罠に違いない。","ENG":"But it's flaunting that wound like bait. It knows we'll go for it.","TWN":"然而那傢伙也刻意露出脖子的傷口，是個明顯的圈套。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"설령 노림수라 하여도… 다른 방법이 없지 않소.","JPN":"たとえ罠だとしても……他の方法がないではないか。","ENG":"Even if it's bait… we don't have a better option.","TWN":"就算是圈套…也沒有其他辦法了不是嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"우리가 범의 목을 베면, 녀석이 기껏 모아둔 힘은 허수가 되어 흩어질 테지.","JPN":"俺たちが虎の首を斬れば、やつが蓄えた力は虚数となって散らばるだろう。","ENG":"If we sever its neck, all the power it gathered will become imaginary and disperse.","TWN":"如果我們斬下老虎的頭，牠辛苦積累的力量就會變成虛數而消散。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"저 장막 너머엔 아직 지켜야 할 사람들이 있으니…","JPN":"あのバリアの向こうには、守るべき人々がいる……","ENG":"And beyond that barrier, there are still people who need protection…","TWN":"在那道屏障後面還有需要守護的人們…"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그들을 살릴 수만 있다면, 바라던 바요.","JPN":"彼らを助けることができるなら本望だ。","ENG":"If this can protect them, then it's worth everything.","TWN":"只要能拯救他們，那就值得了。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"대의를 지키는 것도 훌륭한 자세다만.","JPN":"大義を守るのも立派だが。","ENG":"Protecting the greater good is noble and all.","TWN":"守護大義固然很好。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"기왕 하나 뿐인 목숨을 걸 테면, 네가 진정으로 원하는 그림을 그려봐야 하지 않겠느냐?","JPN":"せっかく1つしかない命をかけるなら、お前が真に望む未来に、手を伸ばしてはみないか？","ENG":"But if you're going to stake your life, shouldn't it be on the future you actually want?","TWN":"但既然要賭上這條僅有一次的性命，難道不該描繪一個你真正想要實現的畫面嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"}}}}]`);export{e as default};